use std::f64::consts::PI;
use std::io::{self, Read};

// ============================================================================
// REALCOMPARE - Reference implementation (do not modify logic)
// ============================================================================

pub const LT: &str = "LT";
pub const EQ: &str = "EQ";
pub const GT: &str = "GT";

pub fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

// ============================================================================
// JSON parsing and output (minimal, no external dependencies)
// ============================================================================

fn parse_json_value(s: &str) -> JsonValue {
    let s = s.trim();
    if s.starts_with('{') {
        parse_json_object(s)
    } else if s.starts_with('[') {
        parse_json_array(s)
    } else if s.starts_with('"') {
        JsonValue::String(parse_json_string(s))
    } else if s == "true" {
        JsonValue::Bool(true)
    } else if s == "false" {
        JsonValue::Bool(false)
    } else if s == "null" {
        JsonValue::Null
    } else {
        JsonValue::Number(s.parse::<f64>().unwrap_or(0.0))
    }
}

fn parse_json_string(s: &str) -> String {
    let s = s.trim();
    if s.len() < 2 {
        return String::new();
    }
    let inner = &s[1..s.len()-1];
    let mut result = String::new();
    let mut chars = inner.chars().peekable();
    while let Some(c) = chars.next() {
        if c == '\\' {
            if let Some(&next) = chars.peek() {
                chars.next();
                match next {
                    'n' => result.push('\n'),
                    'r' => result.push('\r'),
                    't' => result.push('\t'),
                    '"' => result.push('"'),
                    '\\' => result.push('\\'),
                    '/' => result.push('/'),
                    _ => {
                        result.push('\\');
                        result.push(next);
                    }
                }
            }
        } else {
            result.push(c);
        }
    }
    result
}

#[derive(Debug, Clone)]
enum JsonValue {
    Null,
    Bool(bool),
    Number(f64),
    String(String),
    Array(Vec<JsonValue>),
    Object(Vec<(String, JsonValue)>),
}

impl JsonValue {
    fn as_object(&self) -> Option<&Vec<(String, JsonValue)>> {
        if let JsonValue::Object(o) = self { Some(o) } else { None }
    }

    fn as_array(&self) -> Option<&Vec<JsonValue>> {
        if let JsonValue::Array(a) = self { Some(a) } else { None }
    }

    fn as_f64(&self) -> Option<f64> {
        if let JsonValue::Number(n) = self { Some(*n) } else { None }
    }

    fn as_i64(&self) -> Option<i64> {
        if let JsonValue::Number(n) = self { Some(*n as i64) } else { None }
    }

    fn as_bool(&self) -> Option<bool> {
        if let JsonValue::Bool(b) = self { Some(*b) } else { None }
    }

    fn as_str(&self) -> Option<&str> {
        if let JsonValue::String(s) = self { Some(s) } else { None }
    }

    fn get(&self, key: &str) -> Option<&JsonValue> {
        if let JsonValue::Object(o) = self {
            for (k, v) in o {
                if k == key {
                    return Some(v);
                }
            }
        }
        None
    }
}

fn find_matching_bracket(s: &str, open: char, close: char) -> usize {
    let mut depth = 0;
    let mut in_string = false;
    let mut escape = false;
    for (i, c) in s.char_indices() {
        if escape {
            escape = false;
            continue;
        }
        if c == '\\' && in_string {
            escape = true;
            continue;
        }
        if c == '"' {
            in_string = !in_string;
            continue;
        }
        if in_string {
            continue;
        }
        if c == open {
            depth += 1;
        } else if c == close {
            depth -= 1;
            if depth == 0 {
                return i;
            }
        }
    }
    s.len() - 1
}

fn find_string_end(s: &str) -> usize {
    let mut escape = false;
    for (i, c) in s[1..].char_indices() {
        if escape {
            escape = false;
            continue;
        }
        if c == '\\' {
            escape = true;
            continue;
        }
        if c == '"' {
            return i + 2;
        }
    }
    s.len()
}

fn find_value_end(s: &str) -> usize {
    let s = s.trim_start();
    if s.starts_with('{') {
        find_matching_bracket(s, '{', '}') + 1
    } else if s.starts_with('[') {
        find_matching_bracket(s, '[', ']') + 1
    } else if s.starts_with('"') {
        find_string_end(s)
    } else {
        // Number, bool, or null
        let mut end = 0;
        for (i, c) in s.char_indices() {
            if c == ',' || c == '}' || c == ']' || c.is_whitespace() {
                end = i;
                break;
            }
            end = i + 1;
        }
        end
    }
}

fn parse_json_object(s: &str) -> JsonValue {
    let s = s.trim();
    if s.len() < 2 {
        return JsonValue::Object(vec![]);
    }
    let inner = &s[1..s.len()-1];
    let mut result = vec![];
    let mut pos = 0;
    let bytes = inner.as_bytes();

    while pos < inner.len() {
        // Skip whitespace
        while pos < inner.len() && (bytes[pos] as char).is_whitespace() {
            pos += 1;
        }
        if pos >= inner.len() {
            break;
        }

        // Find key
        if bytes[pos] as char != '"' {
            break;
        }
        let key_start = pos;
        let key_end = key_start + find_string_end(&inner[key_start..]);
        let key = parse_json_string(&inner[key_start..key_end]);
        pos = key_end;

        // Skip whitespace and colon
        while pos < inner.len() && ((bytes[pos] as char).is_whitespace() || bytes[pos] as char == ':') {
            pos += 1;
        }

        // Find value
        let value_str = &inner[pos..];
        let value_end = find_value_end(value_str);
        let value = parse_json_value(&value_str[..value_end]);
        result.push((key, value));
        pos += value_end;

        // Skip whitespace and comma
        while pos < inner.len() && ((bytes[pos] as char).is_whitespace() || bytes[pos] as char == ',') {
            pos += 1;
        }
    }

    JsonValue::Object(result)
}

fn parse_json_array(s: &str) -> JsonValue {
    let s = s.trim();
    if s.len() < 2 {
        return JsonValue::Array(vec![]);
    }
    let inner = &s[1..s.len()-1];
    let mut result = vec![];
    let mut pos = 0;
    let bytes = inner.as_bytes();

    while pos < inner.len() {
        // Skip whitespace
        while pos < inner.len() && (bytes[pos] as char).is_whitespace() {
            pos += 1;
        }
        if pos >= inner.len() {
            break;
        }

        // Find value
        let value_str = &inner[pos..];
        let value_end = find_value_end(value_str);
        if value_end == 0 {
            break;
        }
        let value = parse_json_value(&value_str[..value_end]);
        result.push(value);
        pos += value_end;

        // Skip whitespace and comma
        while pos < inner.len() && ((bytes[pos] as char).is_whitespace() || bytes[pos] as char == ',') {
            pos += 1;
        }
    }

    JsonValue::Array(result)
}

// ============================================================================
// Input structures
// ============================================================================

#[derive(Debug)]
struct Parameters {
    length1: f64,
    radius1: f64,
    epsilon: f64,
    area1: f64,
    q_pts: usize,
    quads: usize,
    dist: f64,
    n_pts: usize,
    k_pts: usize,
    a_pts: usize,
    b_pts: usize,
    c_pts: usize,
    d_pts: usize,
    e_pts: usize,
    f_pts: usize,
    g_pts: usize,
    length2: f64,
    radius2: f64,
    area2: f64,
}

#[derive(Debug, Clone, Copy, PartialEq)]
enum Connector {
    NotUsed,
    Orr,
    Andd,
}

#[derive(Debug)]
struct Input {
    numpoints: usize,
    x: Vec<f64>,
    y: Vec<f64>,
    parameters: Parameters,
    lcm: [[Connector; 15]; 15],
    pum_diag: [bool; 15],
}

fn parse_connector(s: &str) -> Connector {
    match s {
        "NOTUSED" => Connector::NotUsed,
        "ORR" => Connector::Orr,
        "ANDD" => Connector::Andd,
        _ => Connector::NotUsed,
    }
}

fn parse_input(json: &JsonValue) -> Input {
    let numpoints = json.get("numpoints").and_then(|v| v.as_i64()).unwrap_or(0) as usize;

    let x: Vec<f64> = json.get("x")
        .and_then(|v| v.as_array())
        .map(|arr| arr.iter().filter_map(|v| v.as_f64()).collect())
        .unwrap_or_default();

    let y: Vec<f64> = json.get("y")
        .and_then(|v| v.as_array())
        .map(|arr| arr.iter().filter_map(|v| v.as_f64()).collect())
        .unwrap_or_default();

    let params_json = json.get("parameters").unwrap();
    let parameters = Parameters {
        length1: params_json.get("LENGTH1").and_then(|v| v.as_f64()).unwrap_or(0.0),
        radius1: params_json.get("RADIUS1").and_then(|v| v.as_f64()).unwrap_or(0.0),
        epsilon: params_json.get("EPSILON").and_then(|v| v.as_f64()).unwrap_or(0.0),
        area1: params_json.get("AREA1").and_then(|v| v.as_f64()).unwrap_or(0.0),
        q_pts: params_json.get("Q_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        quads: params_json.get("QUADS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        dist: params_json.get("DIST").and_then(|v| v.as_f64()).unwrap_or(0.0),
        n_pts: params_json.get("N_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        k_pts: params_json.get("K_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        a_pts: params_json.get("A_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        b_pts: params_json.get("B_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        c_pts: params_json.get("C_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        d_pts: params_json.get("D_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        e_pts: params_json.get("E_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        f_pts: params_json.get("F_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        g_pts: params_json.get("G_PTS").and_then(|v| v.as_i64()).unwrap_or(0) as usize,
        length2: params_json.get("LENGTH2").and_then(|v| v.as_f64()).unwrap_or(0.0),
        radius2: params_json.get("RADIUS2").and_then(|v| v.as_f64()).unwrap_or(0.0),
        area2: params_json.get("AREA2").and_then(|v| v.as_f64()).unwrap_or(0.0),
    };

    let mut lcm = [[Connector::NotUsed; 15]; 15];
    if let Some(lcm_arr) = json.get("lcm").and_then(|v| v.as_array()) {
        for (i, row) in lcm_arr.iter().enumerate() {
            if i >= 15 { break; }
            if let Some(row_arr) = row.as_array() {
                for (j, val) in row_arr.iter().enumerate() {
                    if j >= 15 { break; }
                    if let Some(s) = val.as_str() {
                        lcm[i][j] = parse_connector(s);
                    }
                }
            }
        }
    }

    let mut pum_diag = [false; 15];
    if let Some(diag_arr) = json.get("pum_diag").and_then(|v| v.as_array()) {
        for (i, val) in diag_arr.iter().enumerate() {
            if i >= 15 { break; }
            if let Some(b) = val.as_bool() {
                pum_diag[i] = b;
            }
        }
    }

    Input {
        numpoints,
        x,
        y,
        parameters,
        lcm,
        pum_diag,
    }
}

// ============================================================================
// Geometric helper functions
// ============================================================================

fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    // Using the shoelace formula
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0).abs()
}

fn get_quadrant(x: f64, y: f64) -> usize {
    // Priority: I, II, III, IV
    // Quadrant I: x >= 0, y >= 0
    // Quadrant II: x < 0, y >= 0
    // Quadrant III: x <= 0, y < 0
    // Quadrant IV: x > 0, y < 0
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x <= 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

fn angle_at_vertex(x1: f64, y1: f64, vx: f64, vy: f64, x2: f64, y2: f64) -> Option<f64> {
    // Compute angle at vertex (vx, vy) formed by points (x1, y1), (vx, vy), (x2, y2)
    // Returns None if either point coincides with vertex
    let d1 = distance(x1, y1, vx, vy);
    let d2 = distance(x2, y2, vx, vy);

    if realcompare(d1, 0.0) == EQ || realcompare(d2, 0.0) == EQ {
        return None;
    }

    // Vectors from vertex to each point
    let v1x = x1 - vx;
    let v1y = y1 - vy;
    let v2x = x2 - vx;
    let v2y = y2 - vy;

    // Dot product
    let dot = v1x * v2x + v1y * v2y;

    // Compute cosine of angle
    let cos_angle = dot / (d1 * d2);

    // Clamp to [-1, 1] to handle floating point errors
    let cos_angle = cos_angle.max(-1.0).min(1.0);

    Some(cos_angle.acos())
}

fn circumradius(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    // Compute the circumradius of triangle with vertices (x1,y1), (x2,y2), (x3,y3)
    let a = distance(x1, y1, x2, y2);
    let b = distance(x2, y2, x3, y3);
    let c = distance(x3, y3, x1, y1);

    let area = triangle_area(x1, y1, x2, y2, x3, y3);

    if realcompare(area, 0.0) == EQ {
        // Collinear points - circumradius is infinite, return half the longest side
        return a.max(b).max(c) / 2.0;
    }

    // R = (a * b * c) / (4 * Area)
    (a * b * c) / (4.0 * area)
}

fn min_enclosing_circle_radius(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    // Minimum enclosing circle radius for 3 points
    // It's either the circumradius (if triangle is acute or right)
    // or half the longest side (if triangle is obtuse)

    let a = distance(x2, y2, x3, y3); // opposite to point 1
    let b = distance(x1, y1, x3, y3); // opposite to point 2
    let c = distance(x1, y1, x2, y2); // opposite to point 3

    let a2 = a * a;
    let b2 = b * b;
    let c2 = c * c;

    // Check if any angle is obtuse (or right)
    // An angle is obtuse if the square of the opposite side > sum of squares of other two sides

    // Check angle at point 1 (opposite to a)
    if realcompare(a2, b2 + c2) != LT {
        // Angle at point 1 is >= 90 degrees
        return a / 2.0;
    }

    // Check angle at point 2 (opposite to b)
    if realcompare(b2, a2 + c2) != LT {
        return b / 2.0;
    }

    // Check angle at point 3 (opposite to c)
    if realcompare(c2, a2 + b2) != LT {
        return c / 2.0;
    }

    // All angles are acute, use circumradius
    circumradius(x1, y1, x2, y2, x3, y3)
}

fn point_to_line_distance(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    // Distance from point (px, py) to line defined by points (x1, y1) and (x2, y2)
    let line_len = distance(x1, y1, x2, y2);

    if realcompare(line_len, 0.0) == EQ {
        // Line is actually a point
        return distance(px, py, x1, y1);
    }

    // Using the formula: |((y2-y1)*px - (x2-x1)*py + x2*y1 - y2*x1)| / line_len
    let numerator = ((y2 - y1) * px - (x2 - x1) * py + x2 * y1 - y2 * x1).abs();
    numerator / line_len
}

// ============================================================================
// LIC implementations
// ============================================================================

fn lic1(input: &Input) -> bool {
    // There exists at least one set of two consecutive data points that are a distance
    // greater than LENGTH1 apart.
    let n = input.numpoints;
    let length1 = input.parameters.length1;

    for i in 0..n.saturating_sub(1) {
        let d = distance(input.x[i], input.y[i], input.x[i+1], input.y[i+1]);
        if realcompare(d, length1) == GT {
            return true;
        }
    }
    false
}

fn lic2(input: &Input) -> bool {
    // There exists at least one set of three consecutive data points that cannot all be
    // contained within or on a circle of radius RADIUS1.
    let n = input.numpoints;
    let radius1 = input.parameters.radius1;

    for i in 0..n.saturating_sub(2) {
        let r = min_enclosing_circle_radius(
            input.x[i], input.y[i],
            input.x[i+1], input.y[i+1],
            input.x[i+2], input.y[i+2]
        );
        if realcompare(r, radius1) == GT {
            return true;
        }
    }
    false
}

fn lic3(input: &Input) -> bool {
    // There exists at least one set of three consecutive data points which form an angle such that:
    // angle < (PI - EPSILON), or angle > (PI + EPSILON)
    // The second point is the vertex.
    let n = input.numpoints;
    let epsilon = input.parameters.epsilon;

    for i in 0..n.saturating_sub(2) {
        if let Some(angle) = angle_at_vertex(
            input.x[i], input.y[i],
            input.x[i+1], input.y[i+1],
            input.x[i+2], input.y[i+2]
        ) {
            if realcompare(angle, PI - epsilon) == LT || realcompare(angle, PI + epsilon) == GT {
                return true;
            }
        }
    }
    false
}

fn lic4(input: &Input) -> bool {
    // There exists at least one set of three consecutive data points that are the vertices
    // of a triangle with area greater than AREA1.
    let n = input.numpoints;
    let area1 = input.parameters.area1;

    for i in 0..n.saturating_sub(2) {
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[i+1], input.y[i+1],
            input.x[i+2], input.y[i+2]
        );
        if realcompare(area, area1) == GT {
            return true;
        }
    }
    false
}

fn lic5(input: &Input) -> bool {
    // There exists at least one set of Q_PTS consecutive data points that lie in more than
    // QUADS quadrants.
    let n = input.numpoints;
    let q_pts = input.parameters.q_pts;
    let quads = input.parameters.quads;

    if n < q_pts {
        return false;
    }

    for i in 0..=n.saturating_sub(q_pts) {
        let mut quadrants = [false; 4];
        for j in 0..q_pts {
            let q = get_quadrant(input.x[i+j], input.y[i+j]);
            quadrants[q - 1] = true;
        }
        let num_quads: usize = quadrants.iter().filter(|&&x| x).count();
        if num_quads > quads {
            return true;
        }
    }
    false
}

fn lic6(input: &Input) -> bool {
    // There exists at least one set of two consecutive data points, (X[i], Y[i]) and (X[j], Y[j]),
    // such that X[j] - X[i] < 0 (where i = j - 1).
    let n = input.numpoints;

    for i in 0..n.saturating_sub(1) {
        let diff = input.x[i+1] - input.x[i];
        if realcompare(diff, 0.0) == LT {
            return true;
        }
    }
    false
}

fn lic7(input: &Input) -> bool {
    // There exists at least one set of N_PTS consecutive data points such that at least one
    // of the points lies a distance greater than DIST from the line joining the first and
    // last of these N_PTS points.
    let n = input.numpoints;
    let n_pts = input.parameters.n_pts;
    let dist = input.parameters.dist;

    if n < 3 {
        return false;
    }

    for i in 0..=n.saturating_sub(n_pts) {
        let first_idx = i;
        let last_idx = i + n_pts - 1;

        let x1 = input.x[first_idx];
        let y1 = input.y[first_idx];
        let x2 = input.x[last_idx];
        let y2 = input.y[last_idx];

        let line_len = distance(x1, y1, x2, y2);

        for j in (first_idx + 1)..last_idx {
            let d = if realcompare(line_len, 0.0) == EQ {
                // First and last points coincide
                distance(input.x[j], input.y[j], x1, y1)
            } else {
                point_to_line_distance(input.x[j], input.y[j], x1, y1, x2, y2)
            };

            if realcompare(d, dist) == GT {
                return true;
            }
        }
    }
    false
}

fn lic8(input: &Input) -> bool {
    // There exists at least one set of two data points separated by exactly K_PTS consecutive
    // intervening points that are a distance greater than LENGTH1 apart.
    // Condition is not met when NUMPOINTS < 3.
    let n = input.numpoints;
    let k_pts = input.parameters.k_pts;
    let length1 = input.parameters.length1;

    if n < 3 {
        return false;
    }

    for i in 0..(n.saturating_sub(k_pts + 1)) {
        let j = i + k_pts + 1;
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, length1) == GT {
            return true;
        }
    }
    false
}

fn lic9(input: &Input) -> bool {
    // There exists at least one set of three data points separated by exactly A_PTS and B_PTS
    // consecutive intervening points, respectively, that cannot be contained within or on a
    // circle of radius RADIUS1. Condition is not met when NUMPOINTS < 5.
    let n = input.numpoints;
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let radius1 = input.parameters.radius1;

    if n < 5 {
        return false;
    }

    for i in 0..(n.saturating_sub(a_pts + b_pts + 2)) {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;

        let r = min_enclosing_circle_radius(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k]
        );
        if realcompare(r, radius1) == GT {
            return true;
        }
    }
    false
}

fn lic10(input: &Input) -> bool {
    // There exists at least one set of three data points separated by exactly C_PTS and D_PTS
    // consecutive intervening points, respectively, that form an angle such that:
    // angle < (PI - EPSILON), or angle > (PI + EPSILON)
    // Condition is not met when NUMPOINTS < 5.
    let n = input.numpoints;
    let c_pts = input.parameters.c_pts;
    let d_pts = input.parameters.d_pts;
    let epsilon = input.parameters.epsilon;

    if n < 5 {
        return false;
    }

    for i in 0..(n.saturating_sub(c_pts + d_pts + 2)) {
        let j = i + c_pts + 1;
        let k = j + d_pts + 1;

        if let Some(angle) = angle_at_vertex(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k]
        ) {
            if realcompare(angle, PI - epsilon) == LT || realcompare(angle, PI + epsilon) == GT {
                return true;
            }
        }
    }
    false
}

fn lic11(input: &Input) -> bool {
    // There exists at least one set of three data points separated by exactly E_PTS and F_PTS
    // consecutive intervening points, respectively, that are the vertices of a triangle with
    // area greater than AREA1. Condition is not met when NUMPOINTS < 5.
    let n = input.numpoints;
    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let area1 = input.parameters.area1;

    if n < 5 {
        return false;
    }

    for i in 0..(n.saturating_sub(e_pts + f_pts + 2)) {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;

        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k]
        );
        if realcompare(area, area1) == GT {
            return true;
        }
    }
    false
}

fn lic12(input: &Input) -> bool {
    // There exists at least one set of two data points, separated by exactly G_PTS consecutive
    // intervening points, such that X[j] - X[i] < 0 (where i < j).
    // Condition is not met when NUMPOINTS < 3.
    let n = input.numpoints;
    let g_pts = input.parameters.g_pts;

    if n < 3 {
        return false;
    }

    for i in 0..(n.saturating_sub(g_pts + 1)) {
        let j = i + g_pts + 1;
        let diff = input.x[j] - input.x[i];
        if realcompare(diff, 0.0) == LT {
            return true;
        }
    }
    false
}

fn lic13(input: &Input) -> bool {
    // Part 1: There exists at least one set of two data points, separated by exactly K_PTS
    // consecutive intervening points, which are a distance greater than LENGTH1 apart.
    // Part 2: There exists at least one set of two data points (can be same or different),
    // separated by exactly K_PTS consecutive intervening points, that are a distance less than
    // LENGTH2 apart.
    // Both parts must be true. Condition is not met when NUMPOINTS < 3.
    let n = input.numpoints;
    let k_pts = input.parameters.k_pts;
    let length1 = input.parameters.length1;
    let length2 = input.parameters.length2;

    if n < 3 {
        return false;
    }

    let mut part1 = false;
    let mut part2 = false;

    for i in 0..(n.saturating_sub(k_pts + 1)) {
        let j = i + k_pts + 1;
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, length1) == GT {
            part1 = true;
        }
        if realcompare(d, length2) == LT {
            part2 = true;
        }
        if part1 && part2 {
            return true;
        }
    }

    part1 && part2
}

fn lic14(input: &Input) -> bool {
    // Part 1: There exists at least one set of three data points, separated by exactly A_PTS
    // and B_PTS consecutive intervening points, that cannot be contained within or on a circle
    // of radius RADIUS1.
    // Part 2: There exists at least one set of three data points (can be same or different),
    // separated by exactly A_PTS and B_PTS consecutive intervening points, that can be contained
    // in or on a circle of radius RADIUS2.
    // Both parts must be true. Condition is not met when NUMPOINTS < 5.
    let n = input.numpoints;
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let radius1 = input.parameters.radius1;
    let radius2 = input.parameters.radius2;

    if n < 5 {
        return false;
    }

    let mut part1 = false;
    let mut part2 = false;

    for i in 0..(n.saturating_sub(a_pts + b_pts + 2)) {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;

        let r = min_enclosing_circle_radius(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k]
        );
        if realcompare(r, radius1) == GT {
            part1 = true;
        }
        if realcompare(r, radius2) != GT {
            part2 = true;
        }
        if part1 && part2 {
            return true;
        }
    }

    part1 && part2
}

fn lic15(input: &Input) -> bool {
    // Part 1: There exists at least one set of three data points, separated by exactly E_PTS
    // and F_PTS consecutive intervening points, that are the vertices of a triangle with area
    // greater than AREA1.
    // Part 2: There exist three data points (can be same or different), separated by exactly
    // E_PTS and F_PTS consecutive intervening points, that are the vertices of a triangle with
    // area less than AREA2.
    // Both parts must be true. Condition is not met when NUMPOINTS < 5.
    let n = input.numpoints;
    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let area1 = input.parameters.area1;
    let area2 = input.parameters.area2;

    if n < 5 {
        return false;
    }

    let mut part1 = false;
    let mut part2 = false;

    for i in 0..(n.saturating_sub(e_pts + f_pts + 2)) {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;

        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k]
        );
        if realcompare(area, area1) == GT {
            part1 = true;
        }
        if realcompare(area, area2) == LT {
            part2 = true;
        }
        if part1 && part2 {
            return true;
        }
    }

    part1 && part2
}

// ============================================================================
// DECIDE main logic
// ============================================================================

fn compute_cmv(input: &Input) -> [bool; 15] {
    [
        lic1(input),
        lic2(input),
        lic3(input),
        lic4(input),
        lic5(input),
        lic6(input),
        lic7(input),
        lic8(input),
        lic9(input),
        lic10(input),
        lic11(input),
        lic12(input),
        lic13(input),
        lic14(input),
        lic15(input),
    ]
}

fn compute_pum(cmv: &[bool; 15], lcm: &[[Connector; 15]; 15], pum_diag: &[bool; 15]) -> [[bool; 15]; 15] {
    let mut pum = [[false; 15]; 15];

    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = pum_diag[i];
            } else {
                pum[i][j] = match lcm[i][j] {
                    Connector::NotUsed => true,
                    Connector::Andd => cmv[i] && cmv[j],
                    Connector::Orr => cmv[i] || cmv[j],
                };
            }
        }
    }

    pum
}

fn compute_fuv(pum: &[[bool; 15]; 15]) -> [bool; 15] {
    let mut fuv = [false; 15];

    for i in 0..15 {
        // FUV[i] is true if PUM[i,i] is false OR all elements in row i are true
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&x| x);
        }
    }

    fuv
}

fn compute_launch(fuv: &[bool; 15]) -> bool {
    fuv.iter().all(|&x| x)
}

fn decide(input: &Input) -> (Vec<bool>, Vec<Vec<bool>>, Vec<bool>, bool) {
    let cmv = compute_cmv(input);
    let pum = compute_pum(&cmv, &input.lcm, &input.pum_diag);
    let fuv = compute_fuv(&pum);
    let launch = compute_launch(&fuv);

    (
        cmv.to_vec(),
        pum.iter().map(|row| row.to_vec()).collect(),
        fuv.to_vec(),
        launch
    )
}

