    for (i, &b) in cmv.iter().enumerate() {
        if i > 0 { print!(","); }
        print!("{}", if b { "true" } else { "false" });
    }
    print!("],\"pum\":[");
    for (i, row) in pum.iter().enumerate() {
        if i > 0 { print!(","); }
        print!("[");
        for (j, &b) in row.iter().enumerate() {
            if j > 0 { print!(","); }
            print!("{}", if b { "true" } else { "false" });
        }
        print!("]");
    }
    print!("],\"fuv\":[");
    for (i, &b) in fuv.iter().enumerate() {
        if i > 0 { print!(","); }
        print!("{}", if b { "true" } else { "false" });
    }
    println!("],\"launch\":{}}}", if launch { "true" } else { "false" });
}

